import{_ as t,o,c as i,ag as a}from"./chunks/framework.B9unkguw.js";const _=JSON.parse('{"title":"ESC Calibration (ArduPilot)","description":"","frontmatter":{},"headers":[],"relativePath":"en/qgc-user-guide/setup_view/ardupilot/esc.md","filePath":"en/qgc-user-guide/setup_view/ardupilot/esc.md"}'),r={name:"en/qgc-user-guide/setup_view/ardupilot/esc.md"};function n(l,e,s,c,u,d){return o(),i("div",null,e[0]||(e[0]=[a('<h1 id="esc-calibration-ardupilot" tabindex="-1">ESC Calibration (ArduPilot) <a class="header-anchor" href="#esc-calibration-ardupilot" aria-label="Permalink to &quot;ESC Calibration (ArduPilot)&quot;">​</a></h1><p>The ESC page configures Electronic Speed Controller output parameters and provides ESC calibration for ArduPilot vehicles.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><ul><li><strong>Output type</strong> — PWM output protocol: Normal / OneShot / OneShot125 / DShot150/300/600/1200 (<code>MOT_PWM_TYPE</code>). For QuadPlane VTOL, uses <code>Q_M_PWM_TYPE</code>.</li><li><strong>Output PWM min</strong> — minimum PWM value sent to ESCs (<code>MOT_PWM_MIN</code>)</li><li><strong>Output PWM max</strong> — maximum PWM value sent to ESCs (<code>MOT_PWM_MAX</code>)</li><li><strong>Spin when armed</strong> — motor spin level when armed but not flying (<code>MOT_SPIN_ARM</code>)</li><li><strong>Spin minimum</strong> — minimum spin level during flight (<code>MOT_SPIN_MIN</code>)</li><li><strong>Spin maximum</strong> — maximum spin level (<code>MOT_SPIN_MAX</code>)</li></ul><p>When a DShot output type is selected, additional settings appear:</p><ul><li><strong>DShot ESC type</strong> — ESC protocol variant (<code>SERVO_DSHOT_ESC</code>)</li><li><strong>DShot output rate</strong> — DShot frame rate (<code>SERVO_DSHOT_RATE</code>)</li></ul><h2 id="calibration" tabindex="-1">Calibration <a class="header-anchor" href="#calibration" aria-label="Permalink to &quot;Calibration&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Remove all propellers before calibrating ESCs.</p></div><p>Press the <strong>Calibrate</strong> button to run the ESC calibration procedure. This sets <code>ESC_CALIBRATION = 3</code>, which triggers the ESC to learn the throttle range on the next reboot.</p>',9)]))}const g=t(r,[["render",n]]);export{_ as __pageData,g as default};
